/**
 * Send a notification — stores it in memory, dispatches to all registered adapters,
 * and logs to notification history if enabled.
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

  // Log to history as in-app (always stored in memory)
  if (this.historyService) {
    this.historyService.log({
      notificationId: notification.id,
      recipient: params.recipient,
      channel: 'in-app',
      type: params.type,
      subject: params.subject,
      body: params.body,
      status: 'sent',
      sentAt: notification.sentAt,
    });
  }

  for (const adapter of this.adapters) {
    adapter.send(notification).then(() => {
      if (this.historyService) {
        this.historyService.log({
          notificationId: notification.id,
          recipient: params.recipient,
          channel: adapter.name as 'email' | 'webhook',
          type: params.type,
          subject: params.subject,
          body: params.body,
          status: 'sent',
          sentAt: notification.sentAt,
        });
      }
    }).catch((error) => {
      this.logger.error(`Adapter ${adapter.name} failed: ${error}`);
      if (this.historyService) {
        this.historyService.log({
          notificationId: notification.id,
          recipient: params.recipient,
          channel: adapter.name as 'email' | 'webhook',
          type: params.type,
          subject: params.subject,
          body: params.body,
          status: 'failed',
          sentAt: notification.sentAt,
        });
      }
    });
  }
}

