import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import type { LogNotificationParams } from '../../src/services/notification-history.service.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let service: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    service = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  function createLogParams(overrides?: Partial<LogNotificationParams>): LogNotificationParams {
    return {
      notificationId: 'notif-0001',
      recipient: 'alice@example.com',
      channel: 'email',
      type: 'order-confirmation',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      status: 'sent',
      sentAt: new Date('2026-01-15T10:00:00Z'),
      ...overrides,
    };
  }

  describe('log', () => {
    it('should log a notification and return the entry', () => {
      const entry = service.log(createLogParams());

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.createdAt).toBeInstanceOf(Date);
    });

    it('should generate sequential IDs', () => {
      const entry1 = service.log(createLogParams());
      const entry2 = service.log(createLogParams({ notificationId: 'notif-0002' }));

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });

    it('should persist entries to the repository', () => {
      service.log(createLogParams());

      expect(service.getCount()).toBe(1);
      expect(repository.count()).toBe(1);
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', () => {
      service.log(createLogParams({ recipient: 'alice@example.com' }));
      service.log(createLogParams({ recipient: 'bob@example.com', notificationId: 'notif-0002' }));
      service.log(createLogParams({ recipient: 'alice@example.com', notificationId: 'notif-0003' }));

      const aliceLogs = service.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);
    });

    it('should return empty array for unknown recipient', () => {
      service.log(createLogParams());

      expect(service.getByRecipient('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('getByType', () => {
    it('should return logs for a specific type', () => {
      service.log(createLogParams({ type: 'order-confirmation' }));
      service.log(createLogParams({ type: 'order-status-update', notificationId: 'notif-0002' }));
      service.log(createLogParams({ type: 'order-confirmation', notificationId: 'notif-0003' }));

      const confirmations = service.getByType('order-confirmation');
      expect(confirmations).toHaveLength(2);
      expect(confirmations.every((l) => l.type === 'order-confirmation')).toBe(true);
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within a date range', () => {
      service.log(createLogParams({ sentAt: new Date('2026-01-10T10:00:00Z') }));
      service.log(createLogParams({
        sentAt: new Date('2026-01-15T10:00:00Z'),
        notificationId: 'notif-0002',
      }));
      service.log(createLogParams({
        sentAt: new Date('2026-01-20T10:00:00Z'),
        notificationId: 'notif-0003',
      }));

      const results = service.getByDateRange(
        new Date('2026-01-12T00:00:00Z'),
        new Date('2026-01-18T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should include boundary dates', () => {
      const sentAt = new Date('2026-01-15T10:00:00Z');
      service.log(createLogParams({ sentAt }));

      const results = service.getByDateRange(sentAt, sentAt);
      expect(results).toHaveLength(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      service.log(createLogParams({
        recipient: 'alice@example.com',
        type: 'order-confirmation',
        channel: 'email',
        status: 'sent',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      }));
      service.log(createLogParams({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'order-status-update',
        channel: 'webhook',
        status: 'sent',
        sentAt: new Date('2026-01-16T10:00:00Z'),
      }));
      service.log(createLogParams({
        notificationId: 'notif-0003',
        recipient: 'alice@example.com',
        type: 'order-status-update',
        channel: 'email',
        status: 'failed',
        sentAt: new Date('2026-01-17T10:00:00Z'),
      }));
    });

    it('should filter by recipient', () => {
      const results = service.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by type', () => {
      const results = service.query({ type: 'order-status-update' });
      expect(results).toHaveLength(2);
    });

    it('should filter by channel', () => {
      const results = service.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by status', () => {
      const results = service.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('should filter by date range', () => {
      const results = service.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-17T23:59:59Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = service.query({
        recipient: 'alice@example.com',
        type: 'order-status-update',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should return all entries with empty filter', () => {
      const results = service.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('getById', () => {
    it('should return a log entry by ID', () => {
      service.log(createLogParams());

      const entry = service.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('notif-0001');
    });

    it('should return undefined for unknown ID', () => {
      expect(service.getById('nlog-9999')).toBeUndefined();
    });
  });

  describe('getAll and getCount', () => {
    it('should return all entries', () => {
      service.log(createLogParams());
      service.log(createLogParams({ notificationId: 'notif-0002' }));

      expect(service.getAll()).toHaveLength(2);
      expect(service.getCount()).toBe(2);
    });

    it('should return empty when no entries exist', () => {
      expect(service.getAll()).toHaveLength(0);
      expect(service.getCount()).toBe(0);
    });
  });
});

